<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">dpiAware</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> xmlns</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://schemas.microsoft.com/SMI/2005/WindowsSettings&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;true/PM&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">dpiAware</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
